$changed = 0
foreach ($file in $csFiles) {
    $content = [System.IO.File]::ReadAllText($file.FullName, $enc)
    $orig    = $content
    foreach ($pair in $pairs) {
        if ($pair -eq $null) { continue }
        $searchBytes  = [System.Convert]::FromBase64String($pair[0])
        $replaceBytes = [System.Convert]::FromBase64String($pair[1])
        $search  = [System.Text.Encoding]::UTF8.GetString($searchBytes)
        $replace = [System.Text.Encoding]::UTF8.GetString($replaceBytes)
        if ($content.Contains($search)) {
            $content = $content.Replace($search, $replace)
        }
    }
    if ($content -ne $orig) {
        [System.IO.File]::WriteAllText($file.FullName, $content, $enc)
        Write-Host "  FIXED: $($file.Name)" -ForegroundColor Green
        $changed++
    }
}

Write-Host "Fixed $changed files." -ForegroundColor Cyan
cd $base
dotnet build 2>&1 | Select-Object -Last 4
if ($LASTEXITCODE -eq 0) { Write-Host "Build OK!" -ForegroundColor Green }